import modal
from pydantic import BaseModel
from typing import List, Any

app = modal.App("fastapi-json-transform")

image = modal.Image.debian_slim().pip_install("fastapi")


@app.function(image=image)
@modal.asgi_app()
def fastapi_app():
    from fastapi import FastAPI

    web_app = FastAPI()

    @web_app.get("/")
    async def health():
        return {"status": "ok", "service": "json-transform"}

    class TransformRequest(BaseModel):
        data: List[Any]
        operation: str

    @web_app.post("/transform")
    async def transform(req: TransformRequest):
        if req.operation == "reverse":
            result = list(reversed(req.data))
        elif req.operation == "sort":
            result = sorted(req.data)
        else:
            result = req.data
        return {"result": result}

    return web_app


@app.local_entrypoint()
def main():
    import urllib.request
    import json

    url = fastapi_app.get_url()
    health_url = url.rstrip("/") + "/"

    with urllib.request.urlopen(health_url) as response:
        body = json.loads(response.read().decode())

    print("Health check response:", body)

    output = modal.Dict.from_name("fastapi-json-transform-output", create_if_missing=True)
    output["health_check"] = "ok"
    output["endpoint_deployed"] = True

    print("Stored results in Modal Dict 'fastapi-json-transform-output'")

